public void testJsonElementSubtypeDeserialization() {
  try {
    gson.fromJson("[1,2,3]", JsonPrimitive.class);
    fail();
  } catch (JsonSyntaxException expected) {
    assertEquals("Expected a com.google.gson.JsonPrimitive but was com.google.gson.JsonArray",
        expected.getMessage());
  }
}

public void testJsonElementArrayTypeMismatch() {
  try {
    gson.fromJson("{\"key\":\"value\"}", JsonArray.class);
    fail();
  } catch (JsonSyntaxException expected) {
    assertEquals("Expected a com.google.gson.JsonArray but was com.google.gson.JsonObject",
        expected.getMessage());
  }
}
